import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import axios from 'axios';
import { motion } from 'framer-motion';

const Signup = () => {
    const [formData, setFormData] = useState({ name: '', email: '', password: '', role: 'member' });
    const navigate = useNavigate();

    const handleSignup = async (e) => {
        e.preventDefault();
        try {
            const { data } = await axios.post('http://localhost:5000/api/auth/register', formData);
            localStorage.setItem('token', data.token);
            localStorage.setItem('name', data.name);
            localStorage.setItem('role', data.role);
            window.location.href = '/';
        } catch (err) {
            alert(err.response?.data?.msg || "Signup failed!");
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-[#0f172a] p-6">
            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="bg-white/5 p-10 rounded-3xl border border-white/10 w-full max-w-md backdrop-blur-xl">
                <h2 className="text-3xl font-black text-white mb-8 text-center bg-gradient-to-r from-purple-400 to-pink-500 bg-clip-text text-transparent">JOIN TASK.IO</h2>
                <form onSubmit={handleSignup} className="space-y-4">
                    <input className="w-full p-4 bg-white/5 border border-white/10 rounded-xl text-white" placeholder="Full Name" onChange={e => setFormData({...formData, name: e.target.value})} required/>
                    <input className="w-full p-4 bg-white/5 border border-white/10 rounded-xl text-white" placeholder="Email Address" onChange={e => setFormData({...formData, email: e.target.value})} required/>
                    <input type="password" className="w-full p-4 bg-white/5 border border-white/10 rounded-xl text-white" placeholder="Password" onChange={e => setFormData({...formData, password: e.target.value})} required/>
                    <select className="w-full p-4 bg-[#1e293b] border border-white/10 rounded-xl text-white" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value})}>
                        <option value="member">Team Member</option>
                        <option value="admin">Project Admin</option>
                    </select>
                    <button className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 rounded-xl font-bold text-white shadow-lg transition-all">Create Account</button>
                </form>
                <p className="mt-6 text-center text-gray-400 text-sm">Already have an account? <Link to="/login" className="text-indigo-400 font-bold ml-1">Login</Link></p>
            </motion.div>
        </div>
    );
};

export default Signup;
